-- Meeting: Ricoh // New North: Weekly Meeting (2025-12-11 17:30:00+00)
WITH new_meeting AS (
  INSERT INTO compass_meetings (contract_id, meeting_date, source, external_id, title, participants, duration_seconds, recording_url, transcript, sentiment, raw_metadata, created_at, updated_at)
  VALUES (
    'ade9bb8a-fde3-4756-a63e-11ce7f227292',
    '2025-12-11 17:30:00+00',
    'fireflies',
    '01KBN9DWAKFW4FQ38B6DHKDR5E',
    'Ricoh // New North: Weekly Meeting',
    '{"Roz","Nathalie Mintjens","Lou Bogani"}'::text[],
    1201,
    'https://us02web.zoom.us/j/85828735088?pwd=b9W3cDKwBeJQyK00Qs0iP3vvCmTxIZ.1',
    '{"id":"01KBN9DWAKFW4FQ38B6DHKDR5E","title":"Ricoh // New North: Weekly Meeting","summary":{"notes":"## **File Quality and Color Consistency**\n\nThe team needs to resolve ongoing color inconsistencies and file transfer issues that disrupt brand standards and add manual review time.\n\n- **Roz identified multiple incorrect color uses**, including reds not matching the Ricoh red standard and three different grays where only two should exist in the Info Print Manager brochure (03:05)  \n    - Lou confirmed that original InDesign files embed correct colors, implying the problem arises after file transfer  \n    - Roz suspects Google Docs or file-sharing methods alter colors during export or translation, similar to previous PowerPoint issues  \n    - Lou proposed deleting all extraneous swatches except the three official colors to isolate export issues and test consistency  \n    - Roz and Nathalie plan to test transferring files via a shared transfer folder instead of Google Docs to prevent color shifts and missing elements  \n\n- **Roz highlighted large and inconsistent registration marks on SAP and Oracle logos** that differ across pages, complicating print quality (08:50)  \n    - Lou acknowledged this issue and committed to correcting the size inconsistencies in future files  \n    - Roz emphasized the need for print-friendly formatting, particularly for tab sizes and crease alignment, to avoid visible defects on physical brochures  \n\n- **Roz reported missing links and assets, including icons and logos, causing errors when opening InDesign files** (13:30)  \n    - Nathalie and Lou committed to verifying and completing the asset library within the shared folder  \n    - Roz will open a dedicated transfer folder for Info Print Manager to ensure all updated files and assets are centralized  \n\n## **File Transfer and Workflow Improvements**\n\nImproving file sharing protocols and export settings is critical to reduce rework, maintain brand standards, and speed up production.\n\n- **Lou will review export and packaging settings in InDesign to identify potential causes of color misalignment and missing links during file handoffs** (13:12)  \n    - Testing will include comparing files sent by email versus through the transfer folder to isolate file corruption or distortion points  \n    - Roz will create and share a new transfer folder for Info Print Manager files to centralize and standardize file exchange  \n\n- **The team agreed to move away from Google Docs for final file sharing to prevent automatic color shifts and formatting errors** (07:49)  \n    - Nathalie noted this would require creating a separate transfer folder for Lou as well to streamline handoffs  \n    - Roz plans to perform test runs of file exports using this transfer system to confirm stability before broader rollout  \n\n## **Product Content Updates and Asset Management**\n\nThe team must update marketing collateral with new images and ensure all content reflects the latest branding to improve customer impact.\n\n- **Roz requested using the new Info Print Manager image library created around August 6th in all current and future sales materials** (18:25)  \n    - Lou asked Nathalie to share the updated image library for immediate incorporation into updated files  \n    - Nathalie confirmed the new images are available and will coordinate their inclusion in revised brochures and sales guides  \n\n- **Roz confirmed all comments on the latest sales guide PDFs were visible and accessible, resolving previous technical issues** (14:26)  \n    - The team will continue to use Acrobat for PDF review to avoid prior transfer-related comment visibility problems  \n\n## **Video Production Timeline and Delivery**\n\nA firm deadline for the updated product video is critical to meet pre-holiday internal review and launch schedules.\n\n- **Nathalie confirmed the animation team is actively working on graphic layering for the product video with recent updates implemented** (15:07)  \n    - Roz requested a firm delivery date of **December 18th** to allow internal review on December 19th before the holiday break (16:29)  \n    - Nathalie agreed to ensure the December 18th deadline is met to avoid further delays and enable timely launch preparation  \n    - Roz emphasized the importance of this updated video to refresh the product''s external messaging and maintain competitive positioning  \n\n## **Print Production Considerations**\n\nPrint-specific design adjustments are necessary to ensure physical materials meet quality standards and avoid waste.\n\n- **Roz redesigned the brochure tab layout to be uniform across pages to improve crease alignment during printing** (10:50)  \n    - She explained uneven tab sizes cause noticeable misalignment when folded, harming visual polish  \n    - Lou agreed to adopt the new tab layout and sizing approach going forward for print-friendly formatting  \n    - This adjustment reduces print errors and supports a consistent brand presentation in physical collateral  \n\n## **Team Coordination and Communication**\n\nClear ownership and collaboration are in place to resolve current issues and streamline future workflows.\n\n- **Lou committed to correcting color swatches, export settings, and asset completeness with a goal to resend clean files for review** (18:16)  \n    - Roz will maintain the transfer folder and upload updated InDesign files to facilitate consistent sharing  \n    - Nathalie will support by coordinating asset availability and monitoring delivery timelines for video and collateral  \n    - The team agreed on incremental testing of file transfer methods to identify and fix root causes of recurring formatting problems","outline":null,"keywords":["Ricoh red","file export","InDesign","color consistency","video animation","sales guides"],"overview":"- **File Quality Issues:** Color inconsistencies found in brochures, requiring resolution for brand compliance and quicker reviews.\n\n- **File Transfer Problems:** Suspected file-sharing methods alter colors. New transfer folder proposed to avoid current issues.\n\n- **Asset Management:** Missing links in InDesign files noted. Asset library needs completion for centralized access.\n\n- **Video Deadline Set:** Updated product video launch aimed for December 18th to facilitate internal review before holidays.\n\n- **Print Design Adjustments:** Brochure tab layout redesigned for better crease alignment, reducing printing errors and enhancing quality.\n\n- **Team Responsibilities:** Clear ownership established for addressing color swatches, asset management, and file sharing improvements.","action_items":"\n**Rozalynne Regan**\nUpload updated Info Print Manager InDesign files into the transfer folder for team access (17:00)\nCreate and manage a transfer folder for Info Print Manager assets to improve file sharing and reduce corruption (14:00)\n\n**Lou Bogani**\nDelete all unnecessary color swatches in InDesign files, retain only the approved Ricoh red, gray, and charcoal, and test file exports for color consistency; resend corrected files to Roz (06:00)\nVerify all links, icons, and logos in InDesign files and ensure missing assets are included (13:00)\n\n**Nathalie Mintjens**\nAssist Lou with accessing the new Info Print Manager image library and share it for updates (18:00)\nSet up and provide access to a transfer folder for smoother file exchange and compare differences with files sent via email and Google Docs (08:00)\nEnsure team adheres to deadlines and coordinate final animation video delivery by December 18 for December 19 review (16:00)\n"},"duration":20.020000457763672,"speakers":[{"id":0,"name":"Roz"},{"id":1,"name":"Nathalie Mintjens"},{"id":2,"name":"Lou Bogani"}],"sentences":[{"text":"Things hadn''t fully kicked in until after I got home with my husband, so I was able to be sick at home, which made life better.","index":0,"end_time":9.04,"speaker_id":0,"start_time":0.16,"speaker_name":"Roz"},{"text":"Yeah, slightly.","index":1,"end_time":10.52,"speaker_id":0,"start_time":9.44,"speaker_name":"Roz"},{"text":"But yeah, my, my stomach and I are just not happy with each other.","index":2,"end_time":13.12,"speaker_id":0,"start_time":10.52,"speaker_name":"Roz"},{"text":"So it was obviously something I ate that did not agree.","index":3,"end_time":15.76,"speaker_id":0,"start_time":13.12,"speaker_name":"Roz"},{"text":"And what annoys me more than anything else is that my husband and I more or less ate same kind things and he is blithely going about his world.","index":4,"end_time":24.08,"speaker_id":0,"start_time":16.48,"speaker_name":"Roz"},{"text":"Fresh as a daisy.","index":5,"end_time":26.81,"speaker_id":0,"start_time":25.61,"speaker_name":"Roz"},{"text":"Everything''s fine.","index":6,"end_time":28.41,"speaker_id":0,"start_time":27.05,"speaker_name":"Roz"},{"text":"Like I hate you just a little bit.","index":7,"end_time":33.21,"speaker_id":0,"start_time":30.81,"speaker_name":"Roz"},{"text":"I''m glad it wasn''t on the plane though.","index":8,"end_time":35.41,"speaker_id":1,"start_time":33.77,"speaker_name":"Nathalie Mintjens"},{"text":"That would have been really bad.","index":9,"end_time":36.97,"speaker_id":1,"start_time":35.41,"speaker_name":"Nathalie Mintjens"},{"text":"Well, it''s funny.","index":10,"end_time":38.53,"speaker_id":0,"start_time":37.29,"speaker_name":"Roz"},{"text":"So the, the, like the, the morning before we were supposed.","index":11,"end_time":41.81,"speaker_id":0,"start_time":38.53,"speaker_name":"Roz"},{"text":"We''re set to go and, and our, our flight was at like 7 o'' clock in the morning or something.","index":12,"end_time":48.29,"speaker_id":0,"start_time":41.81,"speaker_name":"Roz"},{"text":"So it was just, you know, horrible.","index":13,"end_time":50.81,"speaker_id":0,"start_time":48.29,"speaker_name":"Roz"},{"text":"I, I don''t do early mornings.","index":14,"end_time":53,"speaker_id":0,"start_time":51.32,"speaker_name":"Roz"},{"text":"Such a bad morning person.","index":15,"end_time":54.12,"speaker_id":0,"start_time":53,"speaker_name":"Roz"},{"text":"But we had to be up like super early.","index":16,"end_time":56.84,"speaker_id":0,"start_time":55.32,"speaker_name":"Roz"},{"text":"So I was already up at like 3 o'' clock in the morning because I just, I felt like hot but cold and I thought, oh God, maybe I''m getting a flu.","index":17,"end_time":64.44,"speaker_id":0,"start_time":57.08,"speaker_name":"Roz"},{"text":"So I''m like, get me home so I can be sick at home.","index":18,"end_time":66.68,"speaker_id":0,"start_time":64.44,"speaker_name":"Roz"},{"text":"Right.","index":19,"end_time":66.92,"speaker_id":0,"start_time":66.68,"speaker_name":"Roz"},{"text":"Like I have a window.","index":20,"end_time":68.12,"speaker_id":0,"start_time":66.92,"speaker_name":"Roz"},{"text":"But it wasn''t until like I got home and things just started to happen rapid fire.","index":21,"end_time":75.16,"speaker_id":0,"start_time":69.4,"speaker_name":"Roz"},{"text":"I was like, oh, okay, this is definitely food poisoning.","index":22,"end_time":79,"speaker_id":0,"start_time":75.32,"speaker_name":"Roz"},{"text":"So.","index":23,"end_time":79.4,"speaker_id":0,"start_time":79,"speaker_name":"Roz"},{"text":"Yeah.","index":24,"end_time":79.88,"speaker_id":1,"start_time":79.4,"speaker_name":"Nathalie Mintjens"},{"text":"Yeah.","index":25,"end_time":80.68,"speaker_id":0,"start_time":80.2,"speaker_name":"Roz"},{"text":"But Mexico City was lovely.","index":26,"end_time":82.2,"speaker_id":0,"start_time":80.68,"speaker_name":"Roz"},{"text":"Okay.","index":27,"end_time":84.36,"speaker_id":1,"start_time":83.8,"speaker_name":"Nathalie Mintjens"},{"text":"So I''m probably going to be muted because I''m with my phone.","index":28,"end_time":89.32,"speaker_id":0,"start_time":85.24,"speaker_name":"Roz"},{"text":"Oh, on the balcony.","index":29,"end_time":90.68,"speaker_id":0,"start_time":89.48,"speaker_name":"Roz"},{"text":"They''re working inside.","index":30,"end_time":91.92,"speaker_id":0,"start_time":90.68,"speaker_name":"Roz"},{"text":"Oh, okay.","index":31,"end_time":92.92,"speaker_id":0,"start_time":91.92,"speaker_name":"Roz"},{"text":"Yeah.","index":32,"end_time":94.2,"speaker_id":2,"start_time":93.72,"speaker_name":"Lou Bogani"},{"text":"My AC unit broke on, on Tuesday and here in Argentina summertime, so temperatures are like super high and, and we were like with a really tiny fan with my girlfriend on the bed.","index":33,"end_time":105.92,"speaker_id":2,"start_time":94.36,"speaker_name":"Lou Bogani"},{"text":"We''re like sweating really bad and.","index":34,"end_time":108.76,"speaker_id":2,"start_time":105.92,"speaker_name":"Lou Bogani"},{"text":"And I had to call the, the technician to like to fix it asap because I''m gonna like.","index":35,"end_time":114.64,"speaker_id":2,"start_time":108.92,"speaker_name":"Lou Bogani"},{"text":"It''s an oven here.","index":36,"end_time":115.88,"speaker_id":2,"start_time":114.64,"speaker_name":"Lou Bogani"},{"text":"Really?","index":37,"end_time":116.44,"speaker_id":0,"start_time":116.04,"speaker_name":"Roz"},{"text":"Yeah.","index":38,"end_time":117.28,"speaker_id":2,"start_time":116.92,"speaker_name":"Lou Bogani"},{"text":"I''m going to mild cooked, whatever.","index":39,"end_time":118.839,"speaker_id":2,"start_time":117.28,"speaker_name":"Lou Bogani"},{"text":"I don''t know.","index":40,"end_time":119.36,"speaker_id":0,"start_time":118.839,"speaker_name":"Roz"},{"text":"I''m gonna be grilled in my.","index":41,"end_time":120.68,"speaker_id":2,"start_time":119.36,"speaker_name":"Lou Bogani"},{"text":"Grilled.","index":42,"end_time":122.28,"speaker_id":0,"start_time":121.56,"speaker_name":"Roz"},{"text":"Yeah.","index":43,"end_time":123.32,"speaker_id":0,"start_time":122.76,"speaker_name":"Roz"},{"text":"All types of cooking?","index":44,"end_time":124.92,"speaker_id":2,"start_time":123.72,"speaker_name":"Lou Bogani"},{"text":"Yes.","index":45,"end_time":125.48,"speaker_id":0,"start_time":125.08,"speaker_name":"Roz"},{"text":"All types of hot, hot things.","index":46,"end_time":127.16,"speaker_id":0,"start_time":125.48,"speaker_name":"Roz"},{"text":"Yes.","index":47,"end_time":127.72,"speaker_id":0,"start_time":127.16,"speaker_name":"Roz"},{"text":"Yes.","index":48,"end_time":128.28,"speaker_id":0,"start_time":127.8,"speaker_name":"Roz"},{"text":"Yeah.","index":49,"end_time":128.84,"speaker_id":0,"start_time":128.28,"speaker_name":"Roz"},{"text":"Oh, goodness me.","index":50,"end_time":131.45,"speaker_id":0,"start_time":130.33,"speaker_name":"Roz"},{"text":"Okay, well, I''m sorry to hear that because yeah, that does suck.","index":51,"end_time":134.17,"speaker_id":0,"start_time":131.45,"speaker_name":"Roz"},{"text":"So.","index":52,"end_time":135.13,"speaker_id":0,"start_time":134.73,"speaker_name":"Roz"},{"text":"Yeah.","index":53,"end_time":135.77,"speaker_id":0,"start_time":135.29,"speaker_name":"Roz"},{"text":"What do you got, Natalie?","index":54,"end_time":139.01,"speaker_id":0,"start_time":137.85,"speaker_name":"Roz"},{"text":"I saw all the stuff you guys sent me while I was away and I think I replied back to them all.","index":55,"end_time":144.09,"speaker_id":0,"start_time":139.01,"speaker_name":"Roz"},{"text":"Yeah.","index":56,"end_time":145.77,"speaker_id":0,"start_time":145.45,"speaker_name":"Roz"},{"text":"The one thing I wanted to touch on when I was going through everything is for, you know, like simple stuff like the Ricoh red not being used where appropriate.","index":57,"end_time":156.73,"speaker_id":0,"start_time":145.77,"speaker_name":"Roz"},{"text":"The grays are all kinds of different colors for The.","index":58,"end_time":160.01,"speaker_id":0,"start_time":156.89,"speaker_name":"Roz"},{"text":"I''m wondering, Nadalie, if it has something to do because I know we''ve talked about it before and I feel like something''s changing with these files.","index":59,"end_time":170.15,"speaker_id":0,"start_time":161.27,"speaker_name":"Roz"},{"text":"Kind of like what happened with the PowerPoints.","index":60,"end_time":172.23,"speaker_id":0,"start_time":170.15,"speaker_name":"Roz"},{"text":"Remember I would show you like what my PowerPoints look like when I got them from you guys and you''re like, oh God, we had no idea.","index":61,"end_time":178.47,"speaker_id":0,"start_time":173.03,"speaker_name":"Roz"},{"text":"And I''m wondering if something like that is happening when you put them in Google Docs.","index":62,"end_time":184.15,"speaker_id":0,"start_time":178.55,"speaker_name":"Roz"},{"text":"Yes, so.","index":63,"end_time":186.41,"speaker_id":1,"start_time":185.59,"speaker_name":"Nathalie Mintjens"},{"text":"So, well, that''s why I think it''s good to have Lou here because Lou specifically.","index":64,"end_time":193.08,"speaker_id":1,"start_time":186.64,"speaker_name":"Nathalie Mintjens"},{"text":"So for this Info Print Manager brochure, as an example, when you''re doing it, like did you go through, for example and make sure that all the reds are Ricoh red and the grays as well?","index":65,"end_time":204.88,"speaker_id":1,"start_time":193.08,"speaker_name":"Nathalie Mintjens"},{"text":"Yes.","index":66,"end_time":206.48,"speaker_id":2,"start_time":206,"speaker_name":"Lou Bogani"},{"text":"So the InDesign files that I get, they are all with the colors that they are embedded.","index":67,"end_time":212.64,"speaker_id":2,"start_time":206.56,"speaker_name":"Lou Bogani"},{"text":"Like it says.","index":68,"end_time":213.4,"speaker_id":2,"start_time":212.64,"speaker_name":"Lou Bogani"},{"text":"RICO red and all that stuff.","index":69,"end_time":217.32,"speaker_id":2,"start_time":215.8,"speaker_name":"Lou Bogani"},{"text":"So I don''t.","index":70,"end_time":218.52,"speaker_id":2,"start_time":217.32,"speaker_name":"Lou Bogani"},{"text":"I use those ones because the red that I got on the brochure, just as an example, like for, it''s, you know, for like we just use the red in some of the con.","index":71,"end_time":228.159,"speaker_id":0,"start_time":219.16,"speaker_name":"Roz"},{"text":"Like some of the titles, right?","index":72,"end_time":229.64,"speaker_id":0,"start_time":228.159,"speaker_name":"Roz"},{"text":"Like some of the content title.","index":73,"end_time":231.12,"speaker_id":0,"start_time":229.64,"speaker_name":"Roz"},{"text":"I''m not talking about like the reds that are in the gradiated balloon because those are three very specific colors that we use for that.","index":74,"end_time":238.36,"speaker_id":0,"start_time":231.12,"speaker_name":"Roz"},{"text":"But yeah, it was like CF something and it was not the, like it wasn''t CF122E or whatever the heck it is.","index":75,"end_time":250.03,"speaker_id":0,"start_time":239.79,"speaker_name":"Roz"},{"text":"It was something completely different.","index":76,"end_time":251.35,"speaker_id":0,"start_time":250.03,"speaker_name":"Roz"},{"text":"And I could tell, I was looking at it and I''m like, that red, I''m like, it just doesn''t look right.","index":77,"end_time":255.51,"speaker_id":0,"start_time":251.35,"speaker_name":"Roz"},{"text":"And so when I checked.","index":78,"end_time":256.55,"speaker_id":0,"start_time":255.51,"speaker_name":"Roz"},{"text":"Wasn''T right on any of the content.","index":79,"end_time":260.11,"speaker_id":0,"start_time":258.11,"speaker_name":"Roz"},{"text":"And then the, the next one was like the reg marks for SAP and Oracle.","index":80,"end_time":266.43,"speaker_id":0,"start_time":261.63,"speaker_name":"Roz"},{"text":"Oracle.","index":81,"end_time":267.28,"speaker_id":0,"start_time":266.76,"speaker_name":"Roz"},{"text":"Oracle.","index":82,"end_time":268.08,"speaker_id":0,"start_time":267.28,"speaker_name":"Roz"},{"text":"Oh my God, I can''t speak.","index":83,"end_time":269.16,"speaker_id":0,"start_time":268.08,"speaker_name":"Roz"},{"text":"Were absolutely massive.","index":84,"end_time":271.08,"speaker_id":0,"start_time":269.24,"speaker_name":"Roz"},{"text":"And I was like, why are they so big when they weren''t big anywhere else?","index":85,"end_time":275.72,"speaker_id":0,"start_time":271.16,"speaker_name":"Roz"},{"text":"You know?","index":86,"end_time":276.16,"speaker_id":0,"start_time":275.72,"speaker_name":"Roz"},{"text":"So that''s why I''m, I''m like, before I lose my mind with the whole.","index":87,"end_time":280.32,"speaker_id":0,"start_time":276.16,"speaker_name":"Roz"},{"text":"Because you guys know how much I love playing like hunt hunt and like find and seek with stuff on files.","index":88,"end_time":286.36,"speaker_id":0,"start_time":280.32,"speaker_name":"Roz"},{"text":"I''m like, what is happening with this?","index":89,"end_time":289.72,"speaker_id":0,"start_time":287.16,"speaker_name":"Roz"},{"text":"Like, why, you know, why is it so different?","index":90,"end_time":293.81,"speaker_id":0,"start_time":289.72,"speaker_name":"Roz"},{"text":"And the only thing I can think of is Google Translate is doing something like what happened with the PowerPoint?","index":91,"end_time":299.69,"speaker_id":0,"start_time":293.81,"speaker_name":"Roz"},{"text":"Yeah, that''s, that''s super weird because I, I definitely double checked the colors and all that stuff.","index":92,"end_time":306.73,"speaker_id":2,"start_time":300.97,"speaker_name":"Lou Bogani"},{"text":"Like we''ve talked about it and like I said, that''s why I was like Before I lose my mind over this, I wanted to talk to you guys first.","index":93,"end_time":312.93,"speaker_id":0,"start_time":306.73,"speaker_name":"Roz"},{"text":"Because, you know, the red was wrong.","index":94,"end_time":315.45,"speaker_id":0,"start_time":312.93,"speaker_name":"Roz"},{"text":"The grays.","index":95,"end_time":316.89,"speaker_id":0,"start_time":316.01,"speaker_name":"Roz"},{"text":"I found like, three different kinds of gray, like hex color on this file.","index":96,"end_time":323.84,"speaker_id":0,"start_time":317.05,"speaker_name":"Roz"},{"text":"And there should only be two.","index":97,"end_time":325.2,"speaker_id":0,"start_time":323.84,"speaker_name":"Roz"},{"text":"It should be the dark gray for everything you''re seeing here.","index":98,"end_time":327.8,"speaker_id":0,"start_time":325.2,"speaker_name":"Roz"},{"text":"And then the 717171 should only be on the very end, right?","index":99,"end_time":333.2,"speaker_id":0,"start_time":327.8,"speaker_name":"Roz"},{"text":"Like, stuff like that.","index":100,"end_time":334.04,"speaker_id":0,"start_time":333.2,"speaker_name":"Roz"},{"text":"Like, this is all very.","index":101,"end_time":335.04,"speaker_id":0,"start_time":334.04,"speaker_name":"Roz"},{"text":"Is the gray.","index":102,"end_time":335.84,"speaker_id":2,"start_time":335.2,"speaker_name":"Lou Bogani"},{"text":"The gray and the charcoal, right?","index":103,"end_time":337.36,"speaker_id":2,"start_time":335.84,"speaker_name":"Lou Bogani"},{"text":"Yeah, yeah, exactly.","index":104,"end_time":339,"speaker_id":0,"start_time":337.76,"speaker_name":"Roz"},{"text":"It''s that light gray and the dark charcoal color that should be it.","index":105,"end_time":342.44,"speaker_id":0,"start_time":339,"speaker_name":"Roz"},{"text":"But I found like, three different other colors while I was in there checking.","index":106,"end_time":345.52,"speaker_id":0,"start_time":342.44,"speaker_name":"Roz"},{"text":"Because I was again, I was looking at it and I was like, what am I seeing?","index":107,"end_time":349.7,"speaker_id":0,"start_time":345.52,"speaker_name":"Roz"},{"text":"You know what I mean?","index":108,"end_time":350.42,"speaker_id":0,"start_time":349.7,"speaker_name":"Roz"},{"text":"Like, it was on a bigger what I Can Do Ross and it wasn''t right.","index":109,"end_time":354.18,"speaker_id":0,"start_time":350.42,"speaker_name":"Roz"},{"text":"So, yeah, it''s weird.","index":110,"end_time":356.26,"speaker_id":0,"start_time":354.58,"speaker_name":"Roz"},{"text":"What I can Do Ross.","index":111,"end_time":358.02,"speaker_id":2,"start_time":356.9,"speaker_name":"Lou Bogani"},{"text":"Like, from.","index":112,"end_time":359.14,"speaker_id":2,"start_time":358.42,"speaker_name":"Lou Bogani"},{"text":"Because I read the mail that you sent us with the corrections.","index":113,"end_time":363.18,"speaker_id":2,"start_time":359.7,"speaker_name":"Lou Bogani"},{"text":"Overall, what I can do is, like, just to be sure and to be like.","index":114,"end_time":368.66,"speaker_id":2,"start_time":363.18,"speaker_name":"Lou Bogani"},{"text":"To make like, from my end things like super simple is delete all the swatches that I have at the InDesign.","index":115,"end_time":376.1,"speaker_id":2,"start_time":368.66,"speaker_name":"Lou Bogani"},{"text":"Whatever swatches that they are.","index":116,"end_time":377.34,"speaker_id":2,"start_time":376.18,"speaker_name":"Lou Bogani"},{"text":"I only use those three.","index":117,"end_time":379.1,"speaker_id":2,"start_time":377.34,"speaker_name":"Lou Bogani"},{"text":"Like, and.","index":118,"end_time":380.78,"speaker_id":2,"start_time":379.98,"speaker_name":"Lou Bogani"},{"text":"And see and see and see if.","index":119,"end_time":383.02,"speaker_id":2,"start_time":380.78,"speaker_name":"Lou Bogani"},{"text":"If that.","index":120,"end_time":383.62,"speaker_id":0,"start_time":383.02,"speaker_name":"Roz"},{"text":"Because there''s a lot of swatches of colors in the file.","index":121,"end_time":386.62,"speaker_id":2,"start_time":383.62,"speaker_name":"Lou Bogani"},{"text":"So maybe kind of messes up with the export.","index":122,"end_time":388.82,"speaker_id":2,"start_time":386.62,"speaker_name":"Lou Bogani"},{"text":"I don''t know.","index":123,"end_time":389.34,"speaker_id":2,"start_time":388.82,"speaker_name":"Lou Bogani"},{"text":"Maybe what I can do is delete everyone.","index":124,"end_time":391.26,"speaker_id":2,"start_time":389.34,"speaker_name":"Lou Bogani"},{"text":"I feel like it''s something like.","index":125,"end_time":393.14,"speaker_id":0,"start_time":391.74,"speaker_name":"Roz"},{"text":"Like I said, what happened with the PowerPoints we use in Google Docs where it was.","index":126,"end_time":396.62,"speaker_id":0,"start_time":393.14,"speaker_name":"Roz"},{"text":"It was shifting everything and it was driving me crazy when I got stuff from you guys because I''m like, why am I seeing it this way?","index":127,"end_time":402.26,"speaker_id":0,"start_time":396.62,"speaker_name":"Roz"},{"text":"And you were like, what are you talking about?","index":128,"end_time":404.38,"speaker_id":0,"start_time":402.26,"speaker_name":"Roz"},{"text":"Until I showed you my screen.","index":129,"end_time":406.14,"speaker_id":0,"start_time":404.7,"speaker_name":"Roz"},{"text":"You were like, oh, God.","index":130,"end_time":407.62,"speaker_id":0,"start_time":406.14,"speaker_name":"Roz"},{"text":"You know, So I have a feeling it''s something along that nature.","index":131,"end_time":410.46,"speaker_id":0,"start_time":407.62,"speaker_name":"Roz"},{"text":"Because we''ve talked about this to the point of me being nauseous about it.","index":132,"end_time":413.86,"speaker_id":0,"start_time":410.46,"speaker_name":"Roz"},{"text":"And I''m sure you guys are sick of hearing it as well.","index":133,"end_time":415.9,"speaker_id":0,"start_time":413.86,"speaker_name":"Roz"},{"text":"But I would be over the moon to get a file where I don''t have to check every single color of every single line.","index":134,"end_time":421.02,"speaker_id":0,"start_time":416.22,"speaker_name":"Roz"},{"text":"Of course that''s going on, right?","index":135,"end_time":422.54,"speaker_id":0,"start_time":421.02,"speaker_name":"Roz"},{"text":"Like, it took me forever to go through this, but I''m like.","index":136,"end_time":424.78,"speaker_id":0,"start_time":422.54,"speaker_name":"Roz"},{"text":"I felt like there was something else happening that was potentially out of our hands.","index":137,"end_time":428.94,"speaker_id":0,"start_time":424.78,"speaker_name":"Roz"},{"text":"You know, I don''t.","index":138,"end_time":429.58,"speaker_id":0,"start_time":428.94,"speaker_name":"Roz"},{"text":"I didn''t feel at all that you guys were going out of your way to, like, use the wrong red.","index":139,"end_time":432.86,"speaker_id":0,"start_time":429.58,"speaker_name":"Roz"},{"text":"Because why?","index":140,"end_time":434.37,"speaker_id":0,"start_time":432.94,"speaker_name":"Roz"},{"text":"Right?","index":141,"end_time":434.77,"speaker_id":0,"start_time":434.37,"speaker_name":"Roz"},{"text":"Yeah.","index":142,"end_time":435.33,"speaker_id":1,"start_time":434.77,"speaker_name":"Nathalie Mintjens"},{"text":"But yeah, if we can maybe do a little bit of like, test driving on stuff like that.","index":143,"end_time":440.21,"speaker_id":0,"start_time":436.05,"speaker_name":"Roz"},{"text":"I don''t know.","index":144,"end_time":441.41,"speaker_id":0,"start_time":440.69,"speaker_name":"Roz"},{"text":"I''ll do that.","index":145,"end_time":443.05,"speaker_id":2,"start_time":442.45,"speaker_name":"Lou Bogani"},{"text":"Ross?","index":146,"end_time":443.49,"speaker_id":0,"start_time":443.05,"speaker_name":"Roz"},{"text":"Yeah.","index":147,"end_time":444.13,"speaker_id":0,"start_time":443.73,"speaker_name":"Roz"},{"text":"I will send you again this file or the file that we got that you gave us a feedback.","index":148,"end_time":448.69,"speaker_id":2,"start_time":444.13,"speaker_name":"Lou Bogani"},{"text":"And I will give you all the files and inside of.","index":149,"end_time":451.89,"speaker_id":2,"start_time":448.69,"speaker_name":"Lou Bogani"},{"text":"Inside the interesting file, I will delete all the swatches besides those three, the charcoal, the gray, and the red.","index":150,"end_time":457.57,"speaker_id":2,"start_time":451.89,"speaker_name":"Lou Bogani"},{"text":"And then we.","index":151,"end_time":458.61,"speaker_id":2,"start_time":458.05,"speaker_name":"Lou Bogani"},{"text":"If we export that and.","index":152,"end_time":459.98,"speaker_id":2,"start_time":458.61,"speaker_name":"Lou Bogani"},{"text":"And we see that there are colors, that they''re kind of different, then we can definitely.","index":153,"end_time":464.05,"speaker_id":2,"start_time":460.05,"speaker_name":"Lou Bogani"},{"text":"Then we can definitely check that it''s the export and we can then go into troubleshooting about that.","index":154,"end_time":469.33,"speaker_id":2,"start_time":464.13,"speaker_name":"Lou Bogani"},{"text":"Yeah.","index":155,"end_time":470.01,"speaker_id":0,"start_time":469.65,"speaker_name":"Roz"},{"text":"Because Natalie and I do have a transfer file that we.","index":156,"end_time":473.01,"speaker_id":0,"start_time":470.01,"speaker_name":"Roz"},{"text":"That we use for, you know, for other things as well.","index":157,"end_time":475.97,"speaker_id":0,"start_time":473.33,"speaker_name":"Roz"},{"text":"If it is Google Docs that''s making this messy, then Natalie, I think we may have to start using that.","index":158,"end_time":481.57,"speaker_id":0,"start_time":476.049,"speaker_name":"Roz"},{"text":"That shared transfer file that you and I have.","index":159,"end_time":483.97,"speaker_id":0,"start_time":481.57,"speaker_name":"Roz"},{"text":"Yeah, that''s what I was thinking too.","index":160,"end_time":486.21,"speaker_id":1,"start_time":484.77,"speaker_name":"Nathalie Mintjens"},{"text":"But that would mean.","index":161,"end_time":487.41,"speaker_id":1,"start_time":486.29,"speaker_name":"Nathalie Mintjens"},{"text":"Creating one for Lou as well, because that''s fine.","index":162,"end_time":491.93,"speaker_id":1,"start_time":488.97,"speaker_name":"Nathalie Mintjens"},{"text":"Lou also sends them to me through Google and then that would be me downloading it.","index":163,"end_time":496.89,"speaker_id":1,"start_time":491.93,"speaker_name":"Nathalie Mintjens"},{"text":"And then that was my next question as I''m like, how do you guys share the file as well?","index":164,"end_time":502.69,"speaker_id":0,"start_time":497.05,"speaker_name":"Roz"},{"text":"Because that could be part of it is that, you know, it''s bouncing through Google Docs or whatever it is, you know, however you guys are doing it.","index":165,"end_time":510.01,"speaker_id":0,"start_time":502.69,"speaker_name":"Roz"},{"text":"And that could be part of the problem as well.","index":166,"end_time":512.53,"speaker_id":0,"start_time":510.01,"speaker_name":"Roz"},{"text":"So if you guys can.","index":167,"end_time":513.69,"speaker_id":0,"start_time":512.53,"speaker_name":"Roz"},{"text":"If we can do a little bit of testing just to see where the crazy is happening.","index":168,"end_time":517.01,"speaker_id":0,"start_time":513.69,"speaker_name":"Roz"},{"text":"Because like I said, this is like a four page document and I was playing hunt and seek and I just drives me crazy and.","index":169,"end_time":524.71,"speaker_id":0,"start_time":517.01,"speaker_name":"Roz"},{"text":"But I''m like, I feel there''s something else going on.","index":170,"end_time":527.23,"speaker_id":0,"start_time":524.71,"speaker_name":"Roz"},{"text":"I think it''s something out of our hands.","index":171,"end_time":529.03,"speaker_id":0,"start_time":527.23,"speaker_name":"Roz"},{"text":"And I remembered what had happened with the PowerPoint.","index":172,"end_time":531.59,"speaker_id":0,"start_time":529.03,"speaker_name":"Roz"},{"text":"So that''s what I just wanted to bring up with you guys.","index":173,"end_time":533.27,"speaker_id":0,"start_time":531.59,"speaker_name":"Roz"},{"text":"I can do a bit of testing just to see like, where that''s happening.","index":174,"end_time":537.03,"speaker_id":0,"start_time":533.27,"speaker_name":"Roz"},{"text":"Because this isn''t obviously the first time.","index":175,"end_time":540.39,"speaker_id":0,"start_time":538.07,"speaker_name":"Roz"},{"text":"Yeah, this isn''t the first time.","index":176,"end_time":541.91,"speaker_id":0,"start_time":540.47,"speaker_name":"Roz"},{"text":"So bypassing all of that, I think I just had some adjustments to be that I made.","index":177,"end_time":548.47,"speaker_id":0,"start_time":542.39,"speaker_name":"Roz"},{"text":"And the file that I sent you, Natalie, via email, like just the rest of it was like adjusting this, you know, top page image, making sure the take control thing was gray instead of red.","index":178,"end_time":559.57,"speaker_id":0,"start_time":548.47,"speaker_name":"Roz"},{"text":"And you know, I reduced, like, you can see, like, if you go down to the second page where it says seamless integration in that first bullet, look at how big those reg marks are.","index":179,"end_time":569.89,"speaker_id":0,"start_time":559.65,"speaker_name":"Roz"},{"text":"Okay.","index":180,"end_time":572.17,"speaker_id":2,"start_time":571.57,"speaker_name":"Lou Bogani"},{"text":"Like, they''re huge.","index":181,"end_time":573.41,"speaker_id":0,"start_time":572.17,"speaker_name":"Roz"},{"text":"You know, What?","index":182,"end_time":573.97,"speaker_id":0,"start_time":573.49,"speaker_name":"Roz"},{"text":"I mean, like, why are they so big?","index":183,"end_time":575.89,"speaker_id":0,"start_time":573.97,"speaker_name":"Roz"},{"text":"Yeah.","index":184,"end_time":577.05,"speaker_id":0,"start_time":576.69,"speaker_name":"Roz"},{"text":"Well.","index":185,"end_time":577.25,"speaker_id":0,"start_time":577.05,"speaker_name":"Roz"},{"text":"Yeah.","index":186,"end_time":577.49,"speaker_id":0,"start_time":577.25,"speaker_name":"Roz"},{"text":"Yeah.","index":187,"end_time":577.69,"speaker_id":0,"start_time":577.49,"speaker_name":"Roz"},{"text":"They''re so super big.","index":188,"end_time":578.73,"speaker_id":2,"start_time":577.69,"speaker_name":"Lou Bogani"},{"text":"I don''t know why.","index":189,"end_time":579.17,"speaker_id":2,"start_time":578.73,"speaker_name":"Lou Bogani"},{"text":"They''re huge, Right?","index":190,"end_time":580.09,"speaker_id":0,"start_time":579.17,"speaker_name":"Roz"},{"text":"And then you look at the SAP right below it where it says SAP, Certified Integration, Immigration.","index":191,"end_time":584.35,"speaker_id":0,"start_time":580.09,"speaker_name":"Roz"},{"text":"And that''s fine.","index":192,"end_time":585.39,"speaker_id":0,"start_time":584.35,"speaker_name":"Roz"},{"text":"I''m like, why are they so big?","index":193,"end_time":587.07,"speaker_id":0,"start_time":585.55,"speaker_name":"Roz"},{"text":"You know?","index":194,"end_time":587.63,"speaker_id":0,"start_time":587.07,"speaker_name":"Roz"},{"text":"Yeah, that''s probably my fault.","index":195,"end_time":589.63,"speaker_id":2,"start_time":587.79,"speaker_name":"Lou Bogani"},{"text":"Well, anyway, I was just like, little things like, that I don''t care about, but the fact that I had to go through everything and make sure that the colors were right drove me a little bit crazy.","index":196,"end_time":599.55,"speaker_id":0,"start_time":590.51,"speaker_name":"Roz"},{"text":"But I''m like, I think it''s something else.","index":197,"end_time":601.27,"speaker_id":0,"start_time":599.55,"speaker_name":"Roz"},{"text":"I don''t think it''s you or me.","index":198,"end_time":602.67,"speaker_id":0,"start_time":601.27,"speaker_name":"Roz"},{"text":"I think it''s something happening in the transfer, like with.","index":199,"end_time":605.35,"speaker_id":0,"start_time":602.67,"speaker_name":"Roz"},{"text":"With the PowerPoints.","index":200,"end_time":606.51,"speaker_id":0,"start_time":605.35,"speaker_name":"Roz"},{"text":"So.","index":201,"end_time":606.99,"speaker_id":0,"start_time":606.59,"speaker_name":"Roz"},{"text":"And then.","index":202,"end_time":609.03,"speaker_id":0,"start_time":608.59,"speaker_name":"Roz"},{"text":"Yeah, the other thing, too, is that with this template.","index":203,"end_time":611.79,"speaker_id":0,"start_time":609.03,"speaker_name":"Roz"},{"text":"With that tab that spans across the top there, like, where that reliable thing is, and then how big you made it on the second page.","index":204,"end_time":620.54,"speaker_id":0,"start_time":613.5,"speaker_name":"Roz"},{"text":"Yeah.","index":205,"end_time":622.7,"speaker_id":0,"start_time":622.3,"speaker_name":"Roz"},{"text":"From like, this.","index":206,"end_time":623.66,"speaker_id":0,"start_time":622.7,"speaker_name":"Roz"},{"text":"So from a print perspective, it''s really tough to get that crease dead on.","index":207,"end_time":631.02,"speaker_id":0,"start_time":623.82,"speaker_name":"Roz"},{"text":"It''s so much easier if it''s just one tap.","index":208,"end_time":633.5,"speaker_id":0,"start_time":631.5,"speaker_name":"Roz"},{"text":"So all I did was I flipped.","index":209,"end_time":634.78,"speaker_id":0,"start_time":633.5,"speaker_name":"Roz"},{"text":"It was like, of the.","index":210,"end_time":637.18,"speaker_id":0,"start_time":634.78,"speaker_name":"Roz"},{"text":"What do you call it, the workflow at the bottom to the top, and then just put all of the bullet points below it, and it made.","index":211,"end_time":644.55,"speaker_id":0,"start_time":637.42,"speaker_name":"Roz"},{"text":"You know, and it worked just fine.","index":212,"end_time":646.07,"speaker_id":0,"start_time":644.55,"speaker_name":"Roz"},{"text":"So if there''s things like that that you need to do with these new templates, by all means.","index":213,"end_time":650.79,"speaker_id":0,"start_time":646.07,"speaker_name":"Roz"},{"text":"So do you want me to expand it up?","index":214,"end_time":652.31,"speaker_id":2,"start_time":650.87,"speaker_name":"Lou Bogani"},{"text":"No, I. I changed it.","index":215,"end_time":654.83,"speaker_id":0,"start_time":653.51,"speaker_name":"Roz"},{"text":"You need to see the new.","index":216,"end_time":655.83,"speaker_id":0,"start_time":654.83,"speaker_name":"Roz"},{"text":"You need to see, like, the new.","index":217,"end_time":658.31,"speaker_id":0,"start_time":656.87,"speaker_name":"Roz"},{"text":"The new copy file that I sent.","index":218,"end_time":660.27,"speaker_id":0,"start_time":658.79,"speaker_name":"Roz"},{"text":"Yeah, go with the new file that I sent.","index":219,"end_time":662.15,"speaker_id":0,"start_time":660.27,"speaker_name":"Roz"},{"text":"You''ll see what I did.","index":220,"end_time":663.11,"speaker_id":0,"start_time":662.15,"speaker_name":"Roz"},{"text":"Okay.","index":221,"end_time":664.11,"speaker_id":2,"start_time":663.67,"speaker_name":"Lou Bogani"},{"text":"Awesome.","index":222,"end_time":664.43,"speaker_id":2,"start_time":664.11,"speaker_name":"Lou Bogani"},{"text":"Yeah, yeah, yeah.","index":223,"end_time":665.99,"speaker_id":0,"start_time":664.43,"speaker_name":"Roz"},{"text":"But just in the future, like, if there''s something like this happening and you''re like, oh, I have to do, like, keep the.","index":224,"end_time":672.84,"speaker_id":0,"start_time":665.99,"speaker_name":"Roz"},{"text":"You know, I don''t mind if this tab across the top needs to become wider, that''s okay.","index":225,"end_time":678.52,"speaker_id":0,"start_time":672.84,"speaker_name":"Roz"},{"text":"But it can''t be like this, where we''ve got one tab, one size and one tab, the other.","index":226,"end_time":683.24,"speaker_id":0,"start_time":678.6,"speaker_name":"Roz"},{"text":"One tab.","index":227,"end_time":683.68,"speaker_id":2,"start_time":683.24,"speaker_name":"Lou Bogani"},{"text":"The other one.","index":228,"end_time":684.12,"speaker_id":2,"start_time":683.68,"speaker_name":"Lou Bogani"},{"text":"Yeah.","index":229,"end_time":684.4,"speaker_id":0,"start_time":684.12,"speaker_name":"Roz"},{"text":"Okay, great.","index":230,"end_time":685.08,"speaker_id":2,"start_time":684.4,"speaker_name":"Lou Bogani"},{"text":"And it only has to do with the print and the crease down the middle, because if the tab spans across, then that crease is much easier to hit.","index":231,"end_time":694.36,"speaker_id":0,"start_time":685.4,"speaker_name":"Roz"},{"text":"Yeah.","index":232,"end_time":694.96,"speaker_id":2,"start_time":694.6,"speaker_name":"Lou Bogani"},{"text":"When you''re printing it.","index":233,"end_time":695.96,"speaker_id":0,"start_time":694.96,"speaker_name":"Roz"},{"text":"Yeah.","index":234,"end_time":696.44,"speaker_id":0,"start_time":695.96,"speaker_name":"Roz"},{"text":"Yeah, that''s it.","index":235,"end_time":698.53,"speaker_id":0,"start_time":697.17,"speaker_name":"Roz"},{"text":"It''s just to do with the printing, because this will look really funny printed out, especially if the crease is off by even, like, a millimeter and it doesn''t hit that gray line.","index":236,"end_time":707.09,"speaker_id":0,"start_time":698.53,"speaker_name":"Roz"},{"text":"It will look.","index":237,"end_time":708.05,"speaker_id":0,"start_time":707.49,"speaker_name":"Roz"},{"text":"Yeah.","index":238,"end_time":708.29,"speaker_id":1,"start_time":708.05,"speaker_name":"Nathalie Mintjens"},{"text":"Definitely.","index":239,"end_time":708.77,"speaker_id":2,"start_time":708.29,"speaker_name":"Lou Bogani"},{"text":"Yeah.","index":240,"end_time":709.53,"speaker_id":0,"start_time":709.09,"speaker_name":"Roz"},{"text":"It will just look awful.","index":241,"end_time":710.61,"speaker_id":0,"start_time":709.53,"speaker_name":"Roz"},{"text":"So.","index":242,"end_time":711.25,"speaker_id":0,"start_time":710.85,"speaker_name":"Roz"},{"text":"Yeah, that''s fine.","index":243,"end_time":712.77,"speaker_id":0,"start_time":711.97,"speaker_name":"Roz"},{"text":"That''s why we do these things, is to go through them.","index":244,"end_time":714.69,"speaker_id":0,"start_time":712.77,"speaker_name":"Roz"},{"text":"So.","index":245,"end_time":715.33,"speaker_id":0,"start_time":714.93,"speaker_name":"Roz"},{"text":"Yeah, anyways.","index":246,"end_time":717.09,"speaker_id":0,"start_time":716.37,"speaker_name":"Roz"},{"text":"Yeah.","index":247,"end_time":717.89,"speaker_id":0,"start_time":717.41,"speaker_name":"Roz"},{"text":"And there''s a list of other things there that I had, but, Yeah, I don''t know.","index":248,"end_time":721.73,"speaker_id":0,"start_time":718.05,"speaker_name":"Roz"},{"text":"Yeah, I''ve gone through them.","index":249,"end_time":722.77,"speaker_id":2,"start_time":721.73,"speaker_name":"Lou Bogani"},{"text":"Yeah.","index":250,"end_time":723.55,"speaker_id":0,"start_time":723.39,"speaker_name":"Roz"},{"text":"I don''t know if Natalie''s giving you the new file, but if not, take a look at it and.","index":251,"end_time":726.67,"speaker_id":0,"start_time":723.55,"speaker_name":"Roz"},{"text":"And you''ll see what, you know, what I did with it.","index":252,"end_time":728.99,"speaker_id":0,"start_time":726.75,"speaker_name":"Roz"},{"text":"And I think it makes a bit more sense for ipm.","index":253,"end_time":731.15,"speaker_id":0,"start_time":728.99,"speaker_name":"Roz"},{"text":"So.","index":254,"end_time":731.95,"speaker_id":0,"start_time":731.55,"speaker_name":"Roz"},{"text":"As a test, Roz, would you like us to.","index":255,"end_time":736.19,"speaker_id":1,"start_time":734.11,"speaker_name":"Nathalie Mintjens"},{"text":"So Lou will, like, go through this one that we made originally.","index":256,"end_time":740.91,"speaker_id":1,"start_time":736.91,"speaker_name":"Nathalie Mintjens"},{"text":"Once again, make sure everything''s right.","index":257,"end_time":742.83,"speaker_id":1,"start_time":740.91,"speaker_name":"Nathalie Mintjens"},{"text":"And then if you set up maybe a transfer file for him, we can see if that helps if it comes through correctly.","index":258,"end_time":748.91,"speaker_id":1,"start_time":743.07,"speaker_name":"Nathalie Mintjens"},{"text":"Well, what I can do.","index":259,"end_time":750.78,"speaker_id":0,"start_time":749.9,"speaker_name":"Roz"},{"text":"Why don''t we do this?","index":260,"end_time":751.66,"speaker_id":0,"start_time":750.78,"speaker_name":"Roz"},{"text":"I already made, like, all the changes I think that needed to be made on this file already.","index":261,"end_time":756.7,"speaker_id":0,"start_time":751.66,"speaker_name":"Roz"},{"text":"I. I just.","index":262,"end_time":758.74,"speaker_id":0,"start_time":758.06,"speaker_name":"Roz"},{"text":"I. I just didn''t have to.","index":263,"end_time":759.98,"speaker_id":0,"start_time":758.74,"speaker_name":"Roz"},{"text":"I needed that.","index":264,"end_time":760.66,"speaker_id":0,"start_time":759.98,"speaker_name":"Roz"},{"text":"I needed.","index":265,"end_time":761.18,"speaker_id":0,"start_time":760.66,"speaker_name":"Roz"},{"text":"Just needed it.","index":266,"end_time":761.9,"speaker_id":0,"start_time":761.18,"speaker_name":"Roz"},{"text":"I needed to have, like, an updated version of this as soon as possible, basically, is what happened.","index":267,"end_time":766.82,"speaker_id":0,"start_time":761.9,"speaker_name":"Roz"},{"text":"So I just did it.","index":268,"end_time":767.86,"speaker_id":0,"start_time":766.82,"speaker_name":"Roz"},{"text":"And I had the time yesterday.","index":269,"end_time":769.18,"speaker_id":0,"start_time":767.86,"speaker_name":"Roz"},{"text":"So why don''t you guys take a look at the file and see if the colors and whatnot are coming through the right way.","index":270,"end_time":776.22,"speaker_id":0,"start_time":769.9,"speaker_name":"Roz"},{"text":"And what I will do is I will set up this file also in the transfer Natalie in our transfer folder and see if there''s a difference between the two.","index":271,"end_time":785.11,"speaker_id":0,"start_time":776.22,"speaker_name":"Roz"},{"text":"Okay, so the one that came on email versus through the transfer folder versus this.","index":272,"end_time":792.31,"speaker_id":1,"start_time":786.39,"speaker_name":"Nathalie Mintjens"},{"text":"I will.","index":273,"end_time":792.75,"speaker_id":2,"start_time":792.39,"speaker_name":"Lou Bogani"},{"text":"I will also.","index":274,"end_time":793.35,"speaker_id":2,"start_time":792.75,"speaker_name":"Lou Bogani"},{"text":"I will also take a look for the export settings, like the package stu